/**
 * Core dispatch: creates a notification record, sends via adapter, emits result event.
 * Checks user preferences before sending if a PreferencesService is configured.
 *
 * Notifications for the same recipient are serialized via a per-recipient queue
 * to guarantee delivery order (e.g., "order placed" always arrives before "payment confirmed").
 */
private async dispatchNotification(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  userId?: string;
}): Promise<void> {
  const recipientKey = params.recipient;
  const previous = this.recipientQueues.get(recipientKey) ?? Promise.resolve();
  const current = previous.then(() => this.doDispatch(params));
  this.recipientQueues.set(recipientKey, current.catch(() => {}));
  return current;
}

private async doDispatch(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  userId?: string;
}): Promise<void> {
  // Check user preferences before sending (per-channel)
  if (this.preferencesService && params.userId) {
    let suppressed = false;

    if (params.channel === 'email') {
      suppressed = !this.preferencesService.shouldSendEmail(params.userId, params.type);
    } else if (params.channel === 'sms') {
      suppressed = !this.preferencesService.shouldSendSms(params.userId, params.type);
    } else if (params.channel === 'webhook') {
      suppressed = !this.preferencesService.shouldSendWebhook(params.userId, params.type);
    }

    if (suppressed) {
      this.logger.info(
        `Notification ${params.type} on ${params.channel} suppressed for user ${params.userId} due to preferences`,
      );
      return;
    }
  }

  const id = generateNotificationId();
  const now = new Date();

  const payload: NotificationPayload = {
    id,
    type: params.type,
    channel: params.channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    metadata: params.metadata,
    createdAt: now,
  };

  const notification: Notification = {
    id,
    type: params.type,
    channel: params.channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    metadata: params.metadata,
    status: 'pending',
    sentAt: now,
  };

  const adapter = this.adapters.get(params.channel);
  if (!adapter) {
    // No adapter registered — store as sent (backwards-compatible in-memory behavior)
    notification.status = 'sent';
    this.notifications.push(notification);
    this.logger.info(`Notification stored: ${id} to ${params.recipient} (no adapter, in-memory only)`);
    return;
  }

  const result = await adapter.send(payload);
  if (result.success) {
    notification.status = 'sent';
    this.notifications.push(notification);
    await this.eventBus.emit({
      type: 'notification:sent',
      notification,
      timestamp: now,
    });
  } else {
    notification.status = 'failed';
    notification.error = result.error;
    this.notifications.push(notification);
    await this.eventBus.emit({
      type: 'notification:failed',
      notification,
      error: result.error ?? 'Unknown error',
      timestamp: now,
    });
  }
}

